import gzip, struct, sys; f = open('{inputs.compressed_file}', 'rb'); header = f.read(1024); index_size = struct.unpack('>I', header[:4])[0]; index_data = header[4:4+index_size]; index = dict((i, struct.unpack('>Q', index_data[i*8:(i+1)*8])[0]) for i in range(index_size//8)); class GSGR:
    def __init__(self, fh, idx):
        self.fh = fh
        self.idx = idx
    def __getitem__(self, key):
        if key not in self.idx:
            raise KeyError(f'Index {key} not found')
        offset = self.idx[key]
        self.fh.seek(offset)
        return gzip.GzipFile(fileobj=self.fh).read()

handler = GSGR(f, index); print(handler[0][:100])
